mapper.select:
/* pv 실제 발전량 조회 */
select
site_id, std_date, sum(gen_val) as gen_val
from (
select
pv_gen_idx, site_id, device_id, std_date, gen_val, temp, reg_date, mod_date
from tb_pv_gen
where site_id = #{siteId}

    and std_date between str_to_date(#{selTermFrom},'%Y%m%d%H%i%s') and
    str_to_date(#{selTermTo},'%Y%m%d%H%i%s')

) a
group by site_id, std_date
order by std_date

/* pv 예측 발전량 조회 */
select
site_id, std_date, sum(gen_val) as gen_val
from (
select
pre_pv_gen_idx, site_id, device_id, std_date, gen_val, temp, reg_date, mod_date
from tb_predict_pv_gen
where site_id = #{siteId}

    and std_date between str_to_date(#{selTermFrom},'%Y%m%d%H%i%s') and
    str_to_date(#{selTermTo},'%Y%m%d%H%i%s')

) a
group by site_id, std_date
order by std_date

SELECT FLOOR(SUM(gen_val) / 1000) as gen_val
FROM tb_pv_gen
where site_id = #{siteId}
  AND YEAR(std_date) = YEAR(NOW())
  AND MONTH(std_date) = MONTH(NOW())
  AND DAY(std_date) = DAY(NOW());
